match:
Array.from(value)
    .filter((char) => {
      const codePoint = char.codePointAt(0) ?? 0;
      return (
        codePoint > 0x1f &&
        (codePoint < 0x7f || codePoint > 0x9f) &&
        codePoint !== 0x2028 &&
        codePoint !== 0x2029
      );
    })
    .join("")
    .trim()
    .slice(0, MAX_PROMPT_MODEL_ID_DISPLAY_CHARS)
